73	def render_tool_events(events: list[str]) -> str:
74	    """Render tool call/result events as an HTML panel."""
75	    if not events:
76	        return ""
77	    rows = []
78	    for ev in events[-12:]:
79	        ev_str = str(ev).strip()
80	        if ev_str.startswith("[TOOL]"):
81	            icon = "→"
82	            text = ev_str[6:].strip()
83	        elif ev_str.startswith("🔧"):
84	            icon = "→"
85	            text = ev_str
86	        elif ev_str.startswith("✅"):
87	            icon = "✓"
88	            text = ev_str
89	        else:
90	            icon = "*"
91	            text = ev_str
92	        rows.append(
93	            f"<div class='galaxy-tool-row'>"
94	            f"<span style='color:#a78bfa;font-weight:bold;'>{icon}</span>"
95	            f"<span>{html.escape(text)}</span></div>"
96	        )
97	    return "<div class='galaxy-tool-panel'>" + "".join(rows) + "</div>"
