102	_MD_IMAGE_RE = _re.compile(r'!\[([^\]]*)\]\(([^)]+)\)')
103	
104	def _resolve_image_paths(content: str) -> str:
105	    """Convert relative image paths to absolute for st.markdown rendering."""
106	    def _resolve(m):
107	        alt = m.group(1)
108	        raw_path = m.group(2).strip()
109	        if raw_path.startswith(('http://', 'https://', 'data:', '/')):
110	            return m.group(0)
111	        try:
112	            p = (DATA_DIR / raw_path).resolve()
113	            if p.exists():
114	                return f'![{alt}]({p.as_posix()})'
115	        except Exception:
116	            pass
117	        try:
118	            from config import GENERATED_DIR
119	            p = (GENERATED_DIR / raw_path).resolve()
120	            if p.exists():
121	                return f'![{alt}]({p.as_posix()})'
122	        except Exception:
123	            pass
124	        try:
125	            p = Path(raw_path).resolve()
126	            if p.exists():
127	                return f'![{alt}]({p.as_posix()})'
128	        except Exception:
129	            pass
130	        return m.group(0)
131	    return _MD_IMAGE_RE.sub(_resolve, content)
