134	def render_mermaid_content(content: str) -> None:
135	    """Render Mermaid diagrams + markdown in a message."""
136	    pattern = _re.compile(r"```mermaid\s*(.*?)```", _re.DOTALL | _re.IGNORECASE)
137	    pos = 0
138	    rendered = False
139	    for match in pattern.finditer(content or ""):
140	        before = content[pos:match.start()]
141	        if before.strip():
142	            st.markdown(_resolve_image_paths(before))
143	        diagram = match.group(1).strip()
144	        if diagram:
145	            rendered = True
146	            safe_diagram = html.escape(diagram)
147	            components.html(
148	                f"""<div class="mermaid">{safe_diagram}</div>
149	                <script type="module">
150	                import mermaid from "https://cdn.jsdelivr.net/npm/mermaid@10/dist/mermaid.esm.min.mjs";
151	                mermaid.initialize({{ startOnLoad: true, securityLevel: "loose", theme: "dark" }});
152	                </script>""",
153	                height=460, scrolling=True,
154	            )
155	        pos = match.end()
156	    rest = (content or "")[pos:]
157	    if rest.strip() or not rendered:
158	        st.markdown(_resolve_image_paths(rest or ""))
159	
