166	def render_attachments(attachments: list[dict]) -> None:
167	    """Render uploaded file attachments."""
168	    for att in attachments or []:
169	        path = DATA_DIR / att.get("path", "")
170	        if att.get("kind") == "image" and path.exists():
171	            st.image(str(path),
172	                     caption=f"{att.get('name')} · {att.get('size', 0)} bytes",
173	                     use_container_width=False)
174	        else:
175	            st.caption(f"📎 {att.get('name')} · {att.get('mime') or 'file'} · "
176	                       f"{att.get('size', 0)} bytes · {att.get('path')}")
