181	def render_permission_selector() -> str:
182	    """Render the permission mode selector. Returns selected mode string."""
183	    from core.enums import PermissionMode
184	    st.markdown("**🔐 权限模式**")
185	    mode = st.radio(
186	        "permission_mode",
187	        ["ask", "guard", "auto"],
188	        horizontal=True,
189	        label_visibility="collapsed",
190	        format_func=lambda m: {
191	            "ask": "🛡 询问", "guard": "🔍 审查", "auto": "🔓 自动",
192	        }[m],
193	        key="chat_permission_mode",
194	    )
195	    if mode == "ask":
196	        st.caption("每次工具调用前确认")
197	    elif mode == "guard":
198	        st.caption("自动执行，事后审查")
199	    else:
200	        st.caption("放行 (危险命令仍拦截)")
201	    return mode
