204	def render_guard_result(guard, retry_count: int = 0, structured=None) -> None:
205	    """Render guard check results in an expander."""
206	    if not guard:
207	        return
208	    decision = getattr(guard, "decision", None)
209	    decision_str = decision.value if hasattr(decision, "value") else str(decision)
210	    score = getattr(guard, "score", 0)
211	    label = f"🛡 Guard: {decision_str}，分数 {score}"
212	    with st.expander(label, expanded=decision_str != "pass"):
213	        st.caption(f"retry_count: {retry_count}")
214	        blocking = getattr(guard, "blocking_issues", [])
215	        warnings = getattr(guard, "warnings", [])
216	        if blocking:
217	            st.markdown("**阻塞问题**")
218	            for item in blocking:
219	                st.markdown(f"- {item}")
220	        if warnings:
221	            st.markdown("**警告**")
222	            for item in warnings:
223	                st.markdown(f"- {item}")
